 For each order, evaluate insertion cost into every existing assignment and a new empty assignment, choose the one with minimal incremental cost, and if none valid, fallback to inserting into the first feasible existing or new assignment. }
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for j := range oris {
		ori := oris[j]
		des := dess[j]
		shipID := total_ship + j

		var bestIncCost float64
		bestIdx := -1
		bestIsNew := false
		found := false

		// Test existing assignments
		for i := 0; i < dispatch.AssignsLen; i++ {
			oldCost := dispatch.Assigns[i].Cost
			if !dispatch.Assigns[i].AddShip(shipID, ori, des) {
				continue
			}
			dispatch.Assigns[i].GenRoute()
			newCost := dispatch.Assigns[i].Cost
			if newCost >= 0 {
				inc := newCost - oldCost
				if !found || inc < bestIncCost {
					bestIncCost = inc
					bestIdx = i
					bestIsNew = false
					found = true
				}
			}
			// revert
			dispatch.Assigns[i].RemoveShip(shipID)
			dispatch.Assigns[i].GenRoute()
		}

		// Test new assignment if capacity left
		if dispatch.AssignsLen < MAXASSIGNS {
			newIdx := dispatch.AssignsLen
			// assume new assignment is empty, Cost = 0, StationsLen = 0
			if dispatch.Assigns[newIdx].AddShip(shipID, ori, des) {
				dispatch.Assigns[newIdx].GenRoute()
				newCost := dispatch.Assigns[newIdx].Cost
				if newCost >= 0 {
					inc := newCost // old cost is 0
					if !found || inc < bestIncCost {
						bestIncCost = inc
						bestIdx = newIdx
						bestIsNew = true
						found = true
					}
				}
				// revert
				dispatch.Assigns[newIdx].RemoveShip(shipID)
				dispatch.Assigns[newIdx].GenRoute()
			}
		}

		// Apply best insertion
		if found {
			if bestIsNew {
				// Create new assignment
				dispatch.Assigns[dispatch.AssignsLen].AddShip(shipID, ori, des)
				dispatch.Assigns[dispatch.AssignsLen].GenRoute()
				dispatch.AssignsLen++
			} else {
				dispatch.Assigns[bestIdx].AddShip(shipID, ori, des)
				dispatch.Assigns[bestIdx].GenRoute()
			}
		} else {
			// Fallback: safe seed-style insertion
			inserted := false
			// Try existing assignments first
			for i := 0; i < dispatch.AssignsLen; i++ {
				if dispatch.Assigns[i].AddShip(shipID, ori, des) {
					dispatch.Assigns[i].GenRoute()
					if dispatch.Assigns[i].Cost >= 0 {
						inserted = true
						break
					} else {
						dispatch.Assigns[i].RemoveShip(shipID)
						dispatch.Assigns[i].GenRoute()
					}
				}
			}
			// Create new assignment if not inserted
			if !inserted && dispatch.AssignsLen < MAXASSIGNS {
				dispatch.Assigns[dispatch.AssignsLen].AddShip(shipID, ori, des)
				dispatch.Assigns[dispatch.AssignsLen].GenRoute()
				// Assume it always succeeds for a single shipment
				dispatch.AssignsLen++
				inserted = true
			}
			// if still not inserted, the order cannot be placed; we proceed without it
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

